848	/// C: `#define luaL_addsize(B,s) ((B)->n += (s))`
849	pub fn add_size(buf: &mut LuaBuffer, sz: usize) {
850	    // PORT NOTE: In C this is a direct `n += sz` on the inline length field.
851	    // With Vec, length is implicit; this is a no-op unless caller wrote past len.
852	    // TODO(port): if direct-write into spare capacity is needed, switch to `unsafe`
