857	/// Pop the string at top of `state`'s stack and append it to `buf`.
858	///
859	/// C: `LUALIB_API void luaL_addvalue(luaL_Buffer *B)`
860	pub fn add_value(state: &mut LuaState, buf: &mut LuaBuffer) -> Result<(), LuaError> {
861	    // C: const char *s = lua_tolstring(L, -1, &len);
862	    if let Some(bytes) = state.peek_bytes(-1) {
863	        let owned = bytes.to_vec();
864	        add_lstring(buf, &owned);
