                        state.set_ci_savedpc(ci, pc);
                        state.set_top(ra + 1);
                        state.gc_cond_step();
                        trap = state.ci_trap(ci);
                    }
                    // ── OP_SELF ───────────────────────────────────────────────
                    // C: ra+1 = rb; if fastget(rb, key) ra=slot else finishget
                    OpCode::Self_ => {
                        let ra = base + i.arg_a();
                        let rb_v = state.get_at(base + i.arg_b()).clone();
