                    OpCode::Add => {
                        let ra = base + i.arg_a();
                        let v1 = state.get_at(base + i.arg_b()).clone();
                        let v2 = state.get_at(base + i.arg_c()).clone();
                        arith_op_aux_rr(state, ra, &v1, &v2, &mut pc,
                            intop_add, |a, b| a + b);
                    }
                    OpCode::Sub => {
                        let ra = base + i.arg_a();
                        let v1 = state.get_at(base + i.arg_b()).clone();
                        let v2 = state.get_at(base + i.arg_c()).clone();
                        arith_op_aux_rr(state, ra, &v1, &v2, &mut pc,
