                    }
                    // ── OP_TBC ────────────────────────────────────────────────
                    // C: halfProtect(luaF_newtbcupval(L, ra));
                    OpCode::Tbc => {
                        let ra = base + i.arg_a();
                        state.set_ci_savedpc(ci, pc);
                        state.set_top(state.ci_top(ci));
